DROP TABLE IF EXISTS `agent_sales`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `agent_sales` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `tenant_id` bigint unsigned DEFAULT NULL,
  `agent_id` bigint unsigned DEFAULT NULL,
  `team_leader_id` bigint unsigned DEFAULT NULL,
  `customer_name` varchar(255) DEFAULT NULL,
  `seller_name` varchar(255) DEFAULT NULL,
  `product_id` bigint unsigned NOT NULL,
  `quantity_sold` int NOT NULL,
  `purchase_price` decimal(15,2) DEFAULT NULL,
  `selling_price` decimal(15,2) DEFAULT NULL,
  `total_purchase_value` decimal(15,2) DEFAULT NULL,
  `total_selling_value` decimal(15,2) DEFAULT NULL,
  `profit` decimal(15,2) DEFAULT NULL,
  `commission_paid` decimal(15,2) DEFAULT NULL,
  `commission_expense_id` bigint unsigned DEFAULT NULL,
  `date_of_collection` date DEFAULT NULL,
  `balance` decimal(15,2) NOT NULL DEFAULT '0.00',
  `payment_option_id` bigint unsigned DEFAULT NULL,
  `stock_remaining` int DEFAULT NULL,
  `date` date NOT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `agent_sales_product_id_foreign` (`product_id`),
  KEY `agent_sales_agent_id_foreign` (`agent_id`),
  KEY `agent_sales_payment_option_id_foreign` (`payment_option_id`),
  KEY `agent_sales_commission_expense_id_foreign` (`commission_expense_id`),
  KEY `agent_sales_tenant_id_index` (`tenant_id`),
  KEY `agent_sales_team_leader_id_foreign` (`team_leader_id`),
  CONSTRAINT `agent_sales_agent_id_foreign` FOREIGN KEY (`agent_id`) REFERENCES `users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `agent_sales_commission_expense_id_foreign` FOREIGN KEY (`commission_expense_id`) REFERENCES `expenses` (`id`) ON DELETE SET NULL,
  CONSTRAINT `agent_sales_payment_option_id_foreign` FOREIGN KEY (`payment_option_id`) REFERENCES `payment_options` (`id`) ON DELETE SET NULL,
  CONSTRAINT `agent_sales_product_id_foreign` FOREIGN KEY (`product_id`) REFERENCES `models` (`id`) ON DELETE CASCADE,
  CONSTRAINT `agent_sales_team_leader_id_foreign` FOREIGN KEY (`team_leader_id`) REFERENCES `users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `agent_sales_tenant_id_foreign` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=19 DEFAULT CHARSET=latin1;
