  KEY `tldr_decided_by_fk` (`decided_by`),
  CONSTRAINT `tldr_decided_by_fk` FOREIGN KEY (`decided_by`) REFERENCES `users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `tldr_from_tl_fk` FOREIGN KEY (`from_team_leader_id`) REFERENCES `users` (`id`) ON DELETE CASCADE,
  CONSTRAINT `tldr_to_rm_fk` FOREIGN KEY (`to_regional_manager_id`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=latin1;
