CREATE TABLE `vendor_registration_intents` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `package_id` bigint unsigned NOT NULL,
  `intent_type` varchar(32) NOT NULL DEFAULT 'registration',
  `vendor_name` varchar(255) NOT NULL,
  `brand_name` varchar(255) DEFAULT NULL,
  `slug` varchar(255) DEFAULT NULL,
  `admin_name` varchar(255) NOT NULL,
  `email` varchar(255) NOT NULL,
  `phone` varchar(32) NOT NULL,
  `password` varchar(255) DEFAULT NULL,
  `payment_phone` varchar(32) DEFAULT NULL,
  `status` varchar(32) NOT NULL DEFAULT 'draft',
  `tenant_id` bigint unsigned DEFAULT NULL,
  `user_id` bigint unsigned DEFAULT NULL,
  `completed_at` timestamp NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `vendor_registration_intents_package_id_foreign` (`package_id`),
  KEY `vendor_registration_intents_tenant_id_foreign` (`tenant_id`),
  KEY `vendor_registration_intents_user_id_foreign` (`user_id`),
  KEY `vendor_registration_intents_email_status_index` (`email`,`status`),
  CONSTRAINT `vendor_registration_intents_package_id_foreign` FOREIGN KEY (`package_id`) REFERENCES `packages` (`id`) ON DELETE CASCADE,
  CONSTRAINT `vendor_registration_intents_tenant_id_foreign` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE SET NULL,
  CONSTRAINT `vendor_registration_intents_user_id_foreign` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=latin1;
